(()=>{document.addEventListener("DOMContentLoaded",()=>{const t=document.getElementById("submit");t.addEventListener("click",()=>{const t=document.querySelector(".needs-validation");if(t.classList.add("was-validated"),t.checkValidity()){const n=document.getElementById("name").value,s=document.getElementById("email").value,o=document.getElementById("phone").value,i=document.getElementById("message").value,a=JSON.stringify({name:n,email:s,phone:o,message:i});e(a,t)}})});function e(e,t){fetch("send_email_contact_page.php",{method:"POST",headers:{"Content-Type":"application/json"},body:e}).then(e=>e.json()).then(e=>{e.success?(alert("Your message has been sent!"),t.reset(),t.classList.remove("was-validated")):alert(`Error: ${e.message}`)}).catch(e=>{console.error("Error:",e),alert("An issue occurred while sending the contact form.")})}})()